var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>3년전, 북방합의체의 어느 연구소</color>","JPN":"<color=#ffd34c>3年前、北方合意体のとある研究所</color>","ENG":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","TWN":"<color=#ffd34c>3年前， 北方和議會某研究所</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"이번에 입대한 아이, 서류 좀 볼까?","JPN":"今度入隊した子、書類を見れるか？","ENG":"Can I see the application form for the child that just enlisted?","TWN":"有關這次入伍的孩子，把資料給我看看？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"네. 박사님.","JPN":"はい、博士。","ENG":"Yes. Doctor.","TWN":"是，博士。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"음… 이름은 ■■. 고아원 출신….","JPN":"ふむ……名前は■■。孤児院出身……","ENG":"Mm... Her name is ■■, and an orphan...","TWN":"嗯……名字是■■，孤兒院出身……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L9_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"입대 동기가 조금 특이해요. 세계평화, 정의 이런 게 적혀있던데요.","JPN":"入隊の志望理由が少し変わっています。世界平和とか正義だとか書かれてましたけど。","ENG":"Her reason for enlisting is a bit peculiar. It's written as \\"world peace and justice.\\"","TWN":"入伍動機有點特別。寫著世界和平、正義之類的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"이번 아이는 얼마나 버틸 것 같으세요?","JPN":"この子はどれくらい持ち堪えられると思いますか？","ENG":"How long do you think she'll last?","TWN":"博士覺得這次的孩子能撐多久？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그건 이제부터 지켜봐야겠지.","JPN":"それはこれからの様子を見るしかないだろう。","ENG":"We'll have to see about that.","TWN":"這個還有待觀察。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"곧 수술을 받게 될 아이와 함께 지내게 되겠는데요.","JPN":"もうすぐ手術を受ける子と一緒に過ごすことになりますね。","ENG":"She'll be sharing a room with another girl who will soon undergo surgery.","TWN":"我們把她安排在雙人房，和另一個即將進行手術的孩子一起住。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"……떠나기 전까진 아이들에게 최대한 잘 대해주게.","JPN":"……ここを出るまで、なるべく子どもたちにはよくしてやってくれ。","ENG":"Make sure to take good care of them until they are sent off.","TWN":"……在送走之前，儘量對孩子們好一點。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그래야 메모리 코어를 제작할 때 편하니까.","JPN":"その方がメモリーコアを製作する時に楽だからな。","ENG":"It'll make creating the memory cores easier.","TWN":"這樣製作記憶核心時會更方便。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知いたしました。","ENG":"Understood.","TWN":"好的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"안녕?","JPN":"こんにちは。","ENG":"Hi.","TWN":"嗨？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"만나서 반가워. 난 네 룸메이트야. 선배이기도 하지.","JPN":"はじめまして。私はあなたのルームメイトだよ。先輩になるね。","ENG":"It's so nice to meet you. I'm your roommate and also your senior.","TWN":"很高興見到你，我是你的室友，也是你的前輩。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"너무 긴장하지 마. 여긴 군사기관이라곤 해도, 딱히 군기 잡는 분위기는 아니거든.","JPN":"あまり緊張しないでね。ここは軍事機関だけど、そんなに堅苦しい雰囲気じゃないから。","ENG":"Don't be so nervous. Even if this place is a military facility, they aren't that strict around here.","TWN":"不要太緊張，雖然這裡是軍事機構，但並沒有特別嚴肅的氛圍。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"저, 전…! 오, 오늘 이곳에 입대한… <color=#ffd34c>마브카</color> 입니다!","JPN":"わ、私は……！　きょ、今日ここに入隊した……<color=#ffd34c>マブカ</color>です！","ENG":"I-I'm...! <color=#ffd34c>Mavka</color>... I just got enlisted today!","TWN":"我，我是……！今，今天剛入伍的……<color=#ffd34c>瑪卡</color>！"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L22_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"아하핫! 그렇게 긴장하지 말라니까~","JPN":"あははっ！　そんなに緊張しなくていいんだよ～","ENG":"Ah hah hah! Relax a little!","TWN":"啊哈哈哈哈！不要那麼緊張嘛～"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"귀여운 이름이네. 얼굴도 이쁘고.","JPN":"素敵な名前だね。お顔も可愛いし。","ENG":"That's a cute name. And you're so pretty.","TWN":"是很美的名字呢，臉也長得很漂亮。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"난 ■■■라고 해. 오늘부터 같이 지낼 사이인데, 잘해보자?","JPN":"私は■■■だよ。今日から一緒に暮らすんだから、仲よくしようね。","ENG":"I'm ■■■. We'll be living together from now on, so let's be friends.","TWN":"我叫■■■，從今天開始我們會一起生活，好好相處吧？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"여긴 카운터를 양성하는 군사기관이지만, 사실상 학교야 학교.","JPN":"ここはカウンターを育成する軍事機関だけど、本当は学校なんだよ。","ENG":"Although this place is a military institution for training Counters, it's just an ordinary school.","TWN":"這裡雖然是培養制裁者的軍事機構，但實際上更像是學校。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"청춘을 즐긴다 생각하면서 느긋하게 있으면 돼.","JPN":"青春を楽しむと思ってゆっくりしていいから。","ENG":"Just think of it as having fun and enjoying life here.","TWN":"就當是在享受青春，放輕鬆點就好。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"그리고 존댓말 쓰지 말아줄래? 솔직히 불편하거든.","JPN":"それと、敬語はやめてくれる？　なんか落ち着かないから。","ENG":"Also, could you stop talking so rigidly to me? It's kinda uncomfortable.","TWN":"還有，說話不用那麼客氣，老實說，我覺得反而有點怪。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"으, 응… 알겠습니다.","JPN":"う、うん……わかりました。","ENG":"U-um... I'll try.","TWN":"嗯，嗯……知道了。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"아하하. 재밌는 아이네. 즐거운 나날이 될 것 같아.","JPN":"あはは。面白い子。毎日楽しくなりそうだね。","ENG":"Ah hah hah! You're funny. I think we're going to have fun together.","TWN":"嘻嘻，真是有趣的孩子。感覺我們在一起會很愉快。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"근데 있지. 선생님께서 난 이제 카운터가 될 거라고 해서, 오래는 못 볼 것 같아.","JPN":"でもね。先生が私はもうすぐカウンターになるって言うから、そう長く一緒にはいられないみたい。","ENG":"But hey. The teacher said that I'm going to become a Counter soon, so we won't be able to spend a lot of time together.","TWN":"不過老師說我馬上就要成為制裁者了，所以可能不會和你相處太久。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"너도 언젠간 이 곳에서 카운터가 될 테니까, 나중에 만나면 꼭 인사해 줘?","JPN":"あなたもいつかここでカウンターになるんだから、再会したら必ず挨拶してね。","ENG":"But you'll also become a Counter one day, so say hi to me when we meet later, okay?","TWN":"你也會在這裡成為制裁者的，以後見面一定要打招呼喔？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"으, 응…! 절대 잊지 않을게… 요!","JPN":"う、うん……！　絶対忘れない……です！","ENG":"O-okay...! I'll never forget... you!","TWN":"嗯，嗯……！絕對不會忘記……的！"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>■■■와 함께했던 나날은 즐거웠다. 정말 학교에라도 온 것 같았다.</color>","JPN":"<color=#ffd34c>■■■と過ごした日々は楽しかった。本当に学校に来たような気分だった。</color>","ENG":"<color=#ffd34c>The days I spent with ■■■ were fun. It really felt like I was at school.</color>","TWN":"<color=#ffd34c>和■■■一起的日子很愉快，真的像是在學校一樣。</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>하지만… 그녀가 떠난 뒤론 단 한 번도 얼굴을 볼 수 없었고,</color>","JPN":"<color=#ffd34c>でも……彼女が去った後、一度も会うことはできなかったし、</color>","ENG":"<color=#ffd34c>But... I wasn't able to see her once after she left.</color>","TWN":"<color=#ffd34c>但是……她離開後，我再也沒有見過她。</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>이후 만나게 된 친구들도 잠깐의 인연만 있을 뿐, 결국 헤어지게 되었다.</color>","JPN":"<color=#ffd34c>それ以後出会った友だちともちょっとした縁があっただけで、結局は別れることになった。</color>","ENG":"<color=#ffd34c>All of my friends I made after were just brief acquaintances, eventually having to say goodbye to all of them.</color>","TWN":"<color=#ffd34c>之後遇到的朋友也只是短暫的緣分，最終還是分開了。</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>모두 훌륭한 카운터가 되어, 국가의 일원이 됐을거라 생각했다.</color>","JPN":"<color=#ffd34c>みんな立派なカウンターになって、国の一員になっていると思った。</color>","ENG":"<color=#ffd34c>I just thought that they all became great Counters and members of the nation.</color>","TWN":"<color=#ffd34c>我想他們都成為了優秀的制裁者，成為了國家的一員。</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>나도… 이곳을 졸업하면, 곧 친구들과 다시 만날거라 생각했다.</color>","JPN":"<color=#ffd34c>私も……ここを卒業したら、すぐにまた友だちと会えると思っていた。</color>","ENG":"<color=#ffd34c>I thought that... I would be able to see them again after I graduate.</color>","TWN":"<color=#ffd34c>我也……以為畢業後會很快再見到朋友們。</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>그런데 이상하네. ■■■가 어떻게 생겼었더라?</color>","JPN":"<color=#ffd34c>でも、おかしいな。■■■って、どんな顔をしてたっけ？</color>","ENG":"<color=#ffd34c>That's odd. What did ■■■ look like?</color>","TWN":"<color=#ffd34c>但是有點奇怪。■■■長什麼樣來著？</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>이후에 들어왔던 애들 얼굴하고… 이름은?</color>","JPN":"<color=#ffd34c>後に入ってきた子どもたちの顔と……名前は？</color>","ENG":"<color=#ffd34c>What about the others that came after...? What were their names?</color>","TWN":"<color=#ffd34c>後進來的那些孩子的臉……名字呢？</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>내 이름이… 정말 마브카였던가…?</color>","JPN":"<color=#ffd34c>私の名前は……本当にマブカだったっけ……？</color>","ENG":"<color=#ffd34c>Was my name... even Mavka...?</color>","TWN":"<color=#ffd34c>我的名字……真的叫瑪卡嗎……？</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>은색 머리에 작은 소녀의 모습….</color>","JPN":"<color=#ffd34c>銀髪に小さな少女の姿……</color>","ENG":"<color=#ffd34c>The silver-haired little girl...</color>","TWN":"<color=#ffd34c>有著銀色頭髮的小女孩……</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>이게 정말… 내 모습이었나…?</color>","JPN":"<color=#ffd34c>これは本当に……私の姿だったっけ……？</color>","ENG":"<color=#ffd34c>Was that... really me...?</color>","TWN":"<color=#ffd34c>這真的是……我的樣子嗎……？</color>"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"마브카. 내일은 중요한 날이니까 일찍 자야 하지 않니?","JPN":"マブカ。明日は重要な日なんだから、早く寝た方がいいんじゃないか？","ENG":"Mavka, tomorrow's a big day. Shouldn't you go to bed early?","TWN":"瑪卡，明天是重要的日子，你應該要早點睡吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그치만… 긴장돼서요.","JPN":"でも……緊張して。","ENG":"But... I'm so anxious.","TWN":"但是……我很緊張。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"제 친구들. 지금쯤 북방의 여러 지역에서 활약하고 있죠?","JPN":"私の友だち。今頃は北方のあちこちで活躍してるんでしょうね。","ENG":"Are my friends doing well across the various sections of the Northern Union?","TWN":"我的朋友們，現在應該在北方的各個地區活躍吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"헤헤… 곧 만나게 될 생각 하니까 많이 설레요.","JPN":"へへ……もうすぐ会えるって思ったら、すごくドキドキします。","ENG":"Hehe... I'm excited to be able to meet them again soon.","TWN":"呵呵……想到馬上就可以和大家見面，覺得好興奮。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그래. 친구들도, 마브카도 정말 우수한 아이였어.","JPN":"そうだな。友だちも、マブカも本当に優秀な子だった。","ENG":"Yes. You and your friends were wonderful kids.","TWN":"是啊，你和你的朋友們，都是非常優秀的孩子。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"선생님도 마브카가 정말 기대되는구나.","JPN":"先生もマブカにはとても期待しているよ。","ENG":"I'm really looking forward to what you'll do, Mavka.","TWN":"老師也對瑪卡充滿了期待。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그치만 여기서 이렇다 할 훈련은 못 받았던 것 같은데요.","JPN":"でも、ここでこれといった訓練は受けなかったような気がします。","ENG":"But I don't think I received any specific training here.","TWN":"不過在這裡好像沒接受過什麼像樣的訓練。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"가끔 주사맞고, 이상한 무기들 좀 써보고… 나머진 공부만 했던 것 같은데…","JPN":"時々注射を打たれたり、変な武器を使ってみたり……あとは勉強ばかりしてたと思うんですけど……","ENG":"All I did was get some shots, use some weird weapons... and study...","TWN":"偶爾打打針，試試奇怪的武器……剩下好像就只有讀書……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"군인한테 총 쏘는 법도 안 가르쳐줄 줄은 몰랐어요.","JPN":"軍人に銃の撃ち方も教えないなんて、知りませんでした。","ENG":"I didn't imagine that you wouldn't teach a soldier how to even shoot a gun.","TWN":"沒想到連怎麼開槍都沒教。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"선생님이 지금까지 살아오며 느낀 게 뭔지 아니?","JPN":"先生が今まで生きてきて、何を感じたかわかるか？","ENG":"Do you know what I've felt living all these years so far?","TWN":"你知道老師活到現在最大的感想是什麼嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"단순히 총 칼만으론 평화에 전혀 도움이 되지 않는다는 거야.","JPN":"単に銃や刀だけでは、平和にまったく役立たないってことだ。","ENG":"It's that a knife or a gun is never helpful for bringing peace.","TWN":"單靠刀槍對和平毫無幫助。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 뭘 하면 도움이 될까요?","JPN":"じゃあ、何をしたら役立つんですか？","ENG":"Then what does help it?","TWN":"那做什麼才有幫助呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그건… 이제부터 함께 알아가자꾸나.","JPN":"それは……今から一緒に考えていこう。","ENG":"That's... something we'll find out from here on out.","TWN":"這個……從現在開始我們一起去發現吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"■■의 메모리 코어 추출은 성공적입니다.","JPN":"実験体■■のメモリーコア抽出は成功です。","ENG":"We have successfully extracted subject ■■'s memory core.","TWN":"實驗體■■的記憶核心提取成功。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"모델명 <color=#ffd34c>마브카</color>에 싱크로 작업 시작하겠습니다.","JPN":"モデル名<color=#ffd34c>マブカ</color>に移植作業を開始します。","ENG":"I will begin the transplant procedure to the <color=#ffd34c>Mavka</color> model.","TWN":"開始移植到<color=#ffd34c>瑪卡</color>型號中。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"■■, 아이의 기억은 전부 마브카로 덮어씌우겠습니다.","JPN":"■■の生前の記憶は、すべて捏造しておきます。","ENG":"All of ■■'s memories will be fabricated.","TWN":"■■的生前記憶已全部篡改完畢。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"음… 싱크로율이 매우 뛰어나네요. 당장 실험에 투입시킬 수 있겠는데요?","JPN":"うーん……すごいシンクロ率ですね。すぐに実験に投入できそうです。","ENG":"Mm... The synchronization is excellent. I think we can begin her experiments right away.","TWN":"嗯……同步率非常高呢，應該可以立刻投入實驗吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"정말 우수한 인형이 되겠어요. 지금까지 애들과는 다르네요.","JPN":"本当に優秀な人形になりそうですよ。今までの子どもたちとは違います。","ENG":"She will make an excellent Doll. She's just different from the others.","TWN":"會成為非常優秀的娃娃呢，和之前的孩子們不一樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"마브카. 천천히 눈을 떠보렴.","JPN":"マブカ。ゆっくり目を開けてみなさい。","ENG":"Mavka? Could you slowly open your eyes?","TWN":"瑪卡，慢慢睜開眼睛吧。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_STEAM"},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마브카. 잘 들리니?</color>","JPN":"<color=#ffd34c>マブカ。ちゃんと聞こえるか？</color>","ENG":"<color=#ffd34c>Mavka, can you hear me?</color>","TWN":"<color=#ffd34c>瑪卡。聽得清嗎？</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>이면세계에 떠돌고 있는 침식체들이 현실로 부상하는 경우가 있어.</color>","JPN":"<color=#ffd34c>裏世界を彷徨っている侵食体が現実に浮上する場合があるんだ。</color>","ENG":"<color=#ffd34c>The C.O.s that reside in the Counterside sometimes emerge into the Normalside.</color>","TWN":"<color=#ffd34c>有時在異界遊蕩的侵蝕體會躍入現世。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>내버려뒀다간 많은 사람들이 다치게 될 거야.</color>","JPN":"<color=#ffd34c>放っておくと、多くの人が怪我をすることになる。</color>","ENG":"<color=#ffd34c>If we don't do anything, they'll hurt a lot of people.</color>","TWN":"<color=#ffd34c>如果放任不管，會有很多人受傷。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마브카의 임무는 이곳의 침식체를 처치하면서 피해를 예방하는 것.</color>","JPN":"<color=#ffd34c>マブカの任務は、ここにいる侵食体を倒しながら被害を予防すること。</color>","ENG":"<color=#ffd34c>Your mission is to exterminate the C.O.s here and prevent any damages, Mavka.</color>","TWN":"<color=#ffd34c>瑪卡的任務就是消滅這些侵蝕體，防止傷害發生。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>현재 신호가 잡히는 침식체는 36마리. 전원 제거해야 해. 할 수 있겠어?</color>","JPN":"<color=#ffd34c>現在信号を捉えている侵食体は36体。すべて除去しなければならない。できるか？</color>","ENG":"<color=#ffd34c>There are currently thirty-six C.O.s detected. You must eliminate all of them. Do you think you can do that?</color>","TWN":"<color=#ffd34c>目前訊號捕捉到的侵蝕體有36隻，必須全部消滅。你能做到嗎？</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"네. 할 수 있어요!","JPN":"はい。できます！","ENG":"Yes. I can do it!","TWN":"是的。我能做到！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>좋아. 부탁한다 마브카.</color>","JPN":"<color=#ffd34c>よし。頼むよ、マブカ。</color>","ENG":"<color=#ffd34c>Good. Then, we're counting on you, Mavka.</color>","TWN":"<color=#ffd34c>好，拜託了，瑪卡。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마브카. 결과 보고해 줘.</color>","JPN":"<color=#ffd34c>マブカ。結果を報告してくれ。</color>","ENG":"<color=#ffd34c>Mavka, report.</color>","TWN":"<color=#ffd34c>瑪卡，報告結果。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"임무… 완료.","JPN":"任務……完了。","ENG":"Mission... complete.","TWN":"任務……完成。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"생체반응… 없음.","JPN":"生体反応……なし。","ENG":"Biosignals... not found.","TWN":"生命反應……無。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>굉장해. 솔직히 이 정도일 줄은 몰랐어.</color>","JPN":"<color=#ffd34c>すごい。正直、ここまでとは思ってなかった。</color>","ENG":"<color=#ffd34c>Amazing. I didn't think she'd be this strong.</color>","TWN":"<color=#ffd34c>真是太棒了。說實話你已經超出了我的預期。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>정말 대견스럽구나 마브카. 국가의 영웅이라 불릴 날도 머지 않겠어.</color>","JPN":"<color=#ffd34c>本当に素晴らしい、マブカ。国の英雄と呼ばれる日もそう遠くないだろう。</color>","ENG":"<color=#ffd34c>I'm so proud of you, Mavka. You will soon be praised as a national hero.</color>","TWN":"<color=#ffd34c>真了不起啊，瑪卡。你成為國家英雄的日子不遠了。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"네! 저… 힘낼게요!","JPN":"はい！　私……頑張ります！","ENG":"Okay! I'll... do my best!","TWN":"是！我……會加油的！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>수술을 받은 것도, 낯선 세상에서 침식체들과 싸우는 것도 전부 국가를 위한 일.</color>","JPN":"<color=#ffd34c>手術を受けたのも、慣れない世界で侵食体と戦うのも全部国のため。</color>","ENG":"<color=#ffd34c>The surgery, and fighting the C.O.s in this strange world were all for my nation.</color>","TWN":"<color=#ffd34c>接受手術也好，在陌生的世界與侵蝕體戰鬥也好，都是為了國家。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>난 세상을 위해, 그리고 정의를 위해 싸우는 거라 생각했어.</color>","JPN":"<color=#ffd34c>私は世界のために、そして正義のために戦ってると思っていた。</color>","ENG":"<color=#ffd34c>I thought I was fighting for justice and for the world.</color>","TWN":"<color=#ffd34c>我一直認為自己是在為世界和正義而戰。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>소멸한 침식체들을 보며 뿌듯함도 느꼈지.</color>","JPN":"<color=#ffd34c>消滅した侵食体を見て、誇らしさも感じた。</color>","ENG":"<color=#ffd34c>I even felt proud looking at the annihilated C.O.s.</color>","TWN":"<color=#ffd34c>看著被消滅的侵蝕體，我也感到自豪。</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>난 의로운 일을 하고 있는거야… 그렇게 믿어왔다.</color>","JPN":"<color=#ffd34c>私は正しいことをしてる……そう信じてきた。</color>","ENG":"<color=#ffd34c>I was doing the righteous thing... Or so I believed.</color>","TWN":"<color=#ffd34c>我一直相信自己在做正義的事…</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"<color=#ffd34c>그날이 있기 전까진….</color>","JPN":"<color=#ffd34c>あの日が来るまでは……</color>","ENG":"<color=#ffd34c>At least until that day...</color>","TWN":"<color=#ffd34c>直到那一天到來之前…</color>"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};